1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
5	
6	const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	};
12	
13	const basePremium = (item: any): number => BASE_PREMIUMS[item.type] ?? 0;
14	
15	const totalComponentPremium = (items: any[]): number => {
16	  const components = items.filter(isComponent);
17	  const counts: Record<string, number> = {};
18	  for (const c of components) {
19	    counts[c.type] = (counts[c.type] ?? 0) + 1;
20	  }
21	  let total = 0;
22	  for (const count of Object.values(counts)) {
23	    if (count === 3) {
24	      total += BLOCK_PREMIUM;
25	    } else {
26	      total += count * COMPONENT_PREMIUM;
27	    }
28	  }
29	  return total;
30	};
31	
32	export const processScenario = (scenario: any): any => {
33	  const results = scenario.steps.map((step: any) => {
34	    const mainItems = step.items.filter((i: any) => !isComponent(i));
35	    const mainTotal = mainItems.reduce(
36	      (sum: number, item: any) => {
37	        const base = basePremium(item);
38	        const cursedSurcharge = item.cursed ? base * 0.5 : 0;
39	        const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
40	        return sum + base + cursedSurcharge + enchantmentSurcharge;
41	      },
42	      0,
43	    );
44	    const compTotal = totalComponentPremium(step.items);
45	    const premium = PROCESSING_FEE + mainTotal + compTotal;
46	    return { premium };
47	  });
48	  return { results };
49	};
